const item = $input.first().json;
const b = item.body && typeof item.body === 'object' ? item.body : item;

const name = String(b.name ?? '').trim();
const email = String(b.email ?? '').trim();
const enquiryText = String(b.message ?? b.enquiry ?? '').trim();
const rawSource = String(b.source ?? '').trim();
const source = rawSource === 'enquiry-form' ? 'website-enquiry' : (rawSource || 'website-enquiry');

if (!name) throw new Error('Name is required');
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) throw new Error('Valid email is required');
if (!enquiryText) throw new Error('Enquiry is required');

const Timestamp = new Date().toISOString();
const smtpFrom = 'robinrawat37@gmail.com';
const emailSubject = 'Thanks for your enquiry — Robin Rawat';
const emailText = [
  'Thank you for reaching out through my website.',
  '',
  'I’ve received your enquiry and will review the details shortly. I’ll get back to you as soon as possible, usually within 24–48 hours.',
  '',
  'In the meantime, if your enquiry is urgent, you can also reach me directly at robinrawat37@gmail.com or +91 9416149624.',
  '',
  'Thanks again for your interest.',
  '',
  'Best regards,',
  'Robin Rawat'
].join('\n');

return [{
  json: {
    Timestamp,
    Name: name,
    Email: email,
    Enquiry: enquiryText,
    Source: source,
    smtpFrom,
    emailSubject,
    emailText
  }
}];
